  1	import { Table, TableVariant, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
  2	import { summaryTitle } from 'pages/Graph/SummaryPanelCommon';
  3	import * as React from 'react';
  4	import { kialiStyle } from 'styles/StyleUtils';
  5	import { renderInOutRateChartHttp, renderInOutRateChartGrpc } from './RateChart';
  6	
  7	const tableStyle = kialiStyle({
  8	  marginBottom: '0.5rem'
  9	});
 10	
 11	type InOutRateTableGrpcPropType = {
 12	  inRate: number;
 13	  inRateGrpcErr: number;
 14	  inRateNR: number;
 15	  outRate: number;
 16	  outRateGrpcErr: number;
 17	  outRateNR: number;
 18	  title: string;
 19	};
 20	
 21	export const InOutRateTableGrpc: React.FC<InOutRateTableGrpcPropType> = (props: InOutRateTableGrpcPropType) => {
 22	  // for the table and graph
 23	  const inErrRate: number = props.inRateGrpcErr + props.inRateNR;
 24	  const outErrRate: number = props.outRateGrpcErr + props.outRateNR;
 25	  const percentErrIn: number = props.inRate === 0 ? 0 : (inErrRate / props.inRate) * 100;
 26	  const percentErrOut: number = props.outRate === 0 ? 0 : (outErrRate / props.outRate) * 100;
 27	  const percentOkIn: number = 100 - percentErrIn;
 28	  const percentOkOut: number = 100 - percentErrOut;
 29	
 30	  return (
 31	    <div>
 32	      <div className={summaryTitle}>{props.title}</div>
 33	
 34	      <Table className={tableStyle}>
 35	        <Thead>
 36	          <Tr>
 37	            <Th />
 38	            <Th dataLabel="Total" textCenter>
 39	              Total
 40	            </Th>
 41	            <Th dataLabel="% Success" textCenter>
 42	              % Success
 43	            </Th>
 44	            <Th dataLabel="% Error" textCenter>
 45	              % Error
 46	            </Th>
 47	          </Tr>
 48	        </Thead>
 49	        <Tbody>
 50	          <Tr>
 51	            <Td>In</Td>
 52	            <Td dataLabel="Total" textCenter>
 53	              {props.inRate.toFixed(2)}
 54	            </Td>
 55	            <Td dataLabel="% Success" textCenter>
 56	              {percentOkIn.toFixed(2)}
 57	            </Td>
 58	            <Td dataLabel="% Error" textCenter>
 59	              {percentErrIn.toFixed(2)}
 60	            </Td>
 61	          </Tr>
 62	          <Tr>
 63	            <Td>Out</Td>
 64	            <Td dataLabel="Total" textCenter>
 65	              {props.outRate.toFixed(2)}
 66	            </Td>
 67	            <Td dataLabel="% Success" textCenter>
 68	              {percentOkOut.toFixed(2)}
 69	            </Td>
 70	            <Td dataLabel="% Error" textCenter>
 71	              {percentErrOut.toFixed(2)}
 72	            </Td>
 73	          </Tr>
 74	        </Tbody>
 75	      </Table>
 76	
 77	      {renderInOutRateChartGrpc(percentOkIn, percentErrIn, percentOkOut, percentErrOut)}
 78	    </div>
 79	  );
 80	};
